     1→//! High-performance design matrix construction for statistical models
     2→//!
     3→//! This crate provides column-oriented design matrix builders that fuse
     4→//! transformations to eliminate intermediate allocations and leverage
     5→//! parallel computation for construction.
     6→
     7→#![forbid(unsafe_code)]
     8→#![warn(missing_docs)]
     9→
    10→use formula::ModelSpec;
    11→use ndarray::Array2;
    12→
    13→/// Design matrix construction errors
    14→#[derive(thiserror::Error, Debug)]
    15→pub enum MatrixError {
    16→    /// Data dimension mismatch
    17→    #[error("Data dimension error: {0}")]
    18→    Dimension(String),
    19→    /// Variable not found in data
    20→    #[error("Variable not found: {0}")]
    21→    VariableNotFound(String),
    22→}
    23→
    24→/// Column-major design matrix builder
    25→pub struct Builder {
    26→    n_rows: usize,
    27→    columns: Vec<Vec<f64>>,
    28→}
    29→
    30→impl Builder {
    31→    /// Create a new builder for the given number of observations
    32→    pub fn new(n_rows: usize) -> Self {
