// For now, let's re-compute it for the example.
let qr = self.x_matrix.col_piv_qr();
let r_mat = qr.R();

// We only need the upper-left `rank x rank` part of R.
let r_rank = r_mat.submatrix(0, 0, self.rank, self.rank);

// Solve R * Z = I to get Z = R⁻¹
let r_inv = r_rank.inverse();

// Now compute (X'X)⁻¹ = R⁻¹ * (R⁻¹)ᵀ
let xtx_inv_stable = &r_inv * r_inv.transpose();

// Standard errors are sqrt of diagonal elements of σ² * (X'X)⁻¹
let std_errors: Vec<f64> = (0..self.rank)
    .map(|i| (mse * xtx_inv_stable[(i, i)]).sqrt().max(0.0)) // Use stable inverse
    .collect();

// Pad std_errors for rank-deficient case if necessary
